function createGoalCycle(name, start, end, approvalEnabled = true, memberScope = "team") {
  return {
    id: `gcycle-${Date.now()}-${Math.random().toString(36).slice(2, 7)}`,
    name,
    start: start || "",
    end: end || "",
    approvalEnabled: !!approvalEnabled,
    readOnly: false,
    status: "active",
    memberScope: memberScope || "team",   // 하위 호환용 (신규는 goalVisibility 사용)
    goalVisibility: {
      member:       { ownTeamMember: true,  ownTeamLead: true,  ownDivOtherTeamLead: false, ownDivOtherTeamMember: false, ownDivHead: false, otherDivHead: false, otherDivMember: false, company: false },
      teamLead:     { ownTeamMember: true,  ownTeamLead: true,  ownDivOtherTeamLead: true,  ownDivOtherTeamMember: false, ownDivHead: true,  otherDivHead: false, otherDivMember: false, company: false },
      divisionHead: { ownTeamMember: true,  ownTeamLead: true,  ownDivOtherTeamLead: true,  ownDivOtherTeamMember: true,  ownDivHead: true,  otherDivHead: true,  otherDivMember: true,  company: true  },
    },
    createdAt: new Date().toISOString(),
  };
}

